import type { Metadata } from "next";
import Link from "next/link";
import { MasonryProjectGrid } from "@/components/MasonryProjectGrid";

export const metadata: Metadata = {
  title: "Gallery Masonry",
  description: "Masonry style portfolio gallery for SR Enterprises project showcase."
};

export default function GalleryMasonryPage() {
  return (
    <main>
      <section className="hero fade-in-up">
        <div className="container">
          <h1>Project Gallery (Masonry)</h1>
          <p className="muted">Alternative brick-style layout to compare with the standard gallery.</p>
          <p>
            <Link href="/gallery" className="cta secondary">
              Back to Standard Gallery
            </Link>
          </p>
        </div>
      </section>
      <section>
        <div className="container">
          <MasonryProjectGrid />
        </div>
      </section>
    </main>
  );
}
